/**
 * Embedding types for md-tldr
 */

// ============================================================================
// Embedding Provider
// ============================================================================

export interface EmbeddingProvider {
  readonly name: string
  readonly dimensions: number
  embed(texts: string[]): Promise<EmbeddingResult>
}

export interface EmbeddingResult {
  readonly embeddings: readonly number[][]
  readonly tokensUsed: number
  readonly cost: number
}

// ============================================================================
// Vector Index
// ============================================================================

export interface VectorEntry {
  readonly id: string
  readonly sectionId: string
  readonly documentPath: string
  readonly heading: string
  readonly embedding: readonly number[]
}

export interface VectorIndex {
  readonly version: number
  readonly provider: string
  readonly dimensions: number
  readonly entries: Record<string, VectorEntry>
  readonly totalCost: number
  readonly totalTokens: number
  readonly createdAt: string
  readonly updatedAt: string
}

// ============================================================================
// Semantic Search
// ============================================================================

export interface SemanticSearchOptions {
  /** Maximum number of results */
  readonly limit?: number | undefined
  /** Minimum similarity threshold (0-1) */
  readonly threshold?: number | undefined
  /** Filter by document path pattern */
  readonly pathPattern?: string | undefined
}

export interface SemanticSearchResult {
  readonly sectionId: string
  readonly documentPath: string
  readonly heading: string
  readonly similarity: number
  readonly content?: string | undefined
}

// ============================================================================
// Errors
// ============================================================================

export interface EmbedError {
  readonly _tag: 'EmbedError'
  readonly cause: 'RateLimit' | 'ApiKey' | 'Network' | 'Unknown'
  readonly message: string
}

export const embedError = (
  cause: EmbedError['cause'],
  message: string,
): EmbedError => ({
  _tag: 'EmbedError',
  cause,
  message,
})

/**
 * OpenAI embedding provider
 */

import OpenAI from 'openai'
import type { EmbeddingProvider, EmbeddingResult } from './types.js'

// ============================================================================
// Cost Constants
// ============================================================================

// Prices per 1M tokens (as of 2024)
const PRICING: Record<string, number> = {
  'text-embedding-3-small': 0.02,
  'text-embedding-3-large': 0.13,
  'text-embedding-ada-002': 0.1,
}

// ============================================================================
// OpenAI Provider
// ============================================================================

export interface OpenAIProviderOptions {
  readonly apiKey?: string | undefined
  readonly model?: string | undefined
  readonly batchSize?: number | undefined
}

export class MissingApiKeyError extends Error {
  constructor() {
    super('OPENAI_API_KEY not set')
    this.name = 'MissingApiKeyError'
  }
}

export class OpenAIProvider implements EmbeddingProvider {
  readonly name: string
  readonly dimensions: number

  private readonly client: OpenAI
  private readonly model: string
  private readonly batchSize: number

  constructor(options: OpenAIProviderOptions = {}) {
    const apiKey = options.apiKey ?? process.env.OPENAI_API_KEY
    if (!apiKey) {
      throw new MissingApiKeyError()
    }

    this.client = new OpenAI({ apiKey })
    this.model = options.model ?? 'text-embedding-3-small'
    this.batchSize = options.batchSize ?? 100
    this.name = `openai:${this.model}`
    this.dimensions = this.model === 'text-embedding-3-large' ? 3072 : 1536
  }

  async embed(texts: string[]): Promise<EmbeddingResult> {
    if (texts.length === 0) {
      return { embeddings: [], tokensUsed: 0, cost: 0 }
    }

    const allEmbeddings: number[][] = []
    let totalTokens = 0

    // Process in batches
    for (let i = 0; i < texts.length; i += this.batchSize) {
      const batch = texts.slice(i, i + this.batchSize)

      const response = await this.client.embeddings.create({
        model: this.model,
        input: batch,
      })

      for (const item of response.data) {
        allEmbeddings.push(item.embedding)
      }

      totalTokens += response.usage?.total_tokens ?? 0
    }

    // Calculate cost
    const pricePerMillion = PRICING[this.model] ?? 0.02
    const cost = (totalTokens / 1_000_000) * pricePerMillion

    return {
      embeddings: allEmbeddings,
      tokensUsed: totalTokens,
      cost,
    }
  }
}

// ============================================================================
// Factory
// ============================================================================

export const createOpenAIProvider = (
  options?: OpenAIProviderOptions,
): EmbeddingProvider => new OpenAIProvider(options)

/**
 * Semantic search functionality
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'
import {
  createStorage,
  loadDocumentIndex,
  loadSectionIndex,
} from '../index/storage.js'
import type { SectionEntry } from '../index/types.js'
import { createOpenAIProvider } from './openai-provider.js'
import type {
  EmbeddingProvider,
  SemanticSearchOptions,
  SemanticSearchResult,
  VectorEntry,
} from './types.js'
import { createVectorStore, type HnswVectorStore } from './vector-store.js'

// ============================================================================
// Embedding Text Generation
// ============================================================================

const generateEmbeddingText = (
  section: SectionEntry,
  content: string,
  documentTitle: string,
  parentHeading?: string | undefined,
): string => {
  const parts: string[] = []

  parts.push(`# ${section.heading}`)
  if (parentHeading) {
    parts.push(`Parent section: ${parentHeading}`)
  }
  parts.push(`Document: ${documentTitle}`)
  parts.push('')
  parts.push(content)

  return parts.join('\n')
}

// ============================================================================
// Cost Estimation
// ============================================================================

// Price per 1M tokens for text-embedding-3-small
const EMBEDDING_PRICE_PER_MILLION = 0.02

export interface DirectoryEstimate {
  readonly directory: string
  readonly fileCount: number
  readonly sectionCount: number
  readonly estimatedTokens: number
  readonly estimatedCost: number
}

export interface EmbeddingEstimate {
  readonly totalFiles: number
  readonly totalSections: number
  readonly totalTokens: number
  readonly totalCost: number
  readonly estimatedTimeSeconds: number
  readonly byDirectory: readonly DirectoryEstimate[]
}

export const estimateEmbeddingCost = (
  rootPath: string,
  options: { excludePatterns?: readonly string[] | undefined } = {},
): Effect.Effect<EmbeddingEstimate, Error> =>
  Effect.gen(function* () {
    const resolvedRoot = path.resolve(rootPath)
    const storage = createStorage(resolvedRoot)

    const docIndex = yield* loadDocumentIndex(storage)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!docIndex || !sectionIndex) {
      return yield* Effect.fail(
        new Error("Index not found. Run 'mdtldr index' first."),
      )
    }

    // Group by directory
    const byDir: Map<
      string,
      { files: Set<string>; sections: number; tokens: number }
    > = new Map()

    for (const section of Object.values(sectionIndex.sections)) {
      // Skip very short sections (< 10 tokens)
      if (section.tokenCount < 10) continue

      // Check exclude patterns
      if (options.excludePatterns?.length) {
        const excluded = options.excludePatterns.some((pattern) => {
          const regex = new RegExp(
            '^' + pattern.replace(/\*/g, '.*').replace(/\?/g, '.') + '$',
          )
          return regex.test(section.documentPath)
        })
        if (excluded) continue
      }

      const dir = path.dirname(section.documentPath) || '.'
      if (!byDir.has(dir)) {
        byDir.set(dir, { files: new Set(), sections: 0, tokens: 0 })
      }
      const entry = byDir.get(dir)!
      entry.files.add(section.documentPath)
      entry.sections++
      entry.tokens += section.tokenCount
    }

    const directoryEstimates: DirectoryEstimate[] = []
    let totalFiles = 0
    let totalSections = 0
    let totalTokens = 0

    for (const [dir, data] of byDir) {
      directoryEstimates.push({
        directory: dir,
        fileCount: data.files.size,
        sectionCount: data.sections,
        estimatedTokens: data.tokens,
        estimatedCost: (data.tokens / 1_000_000) * EMBEDDING_PRICE_PER_MILLION,
      })
      totalFiles += data.files.size
      totalSections += data.sections
      totalTokens += data.tokens
    }

    // Sort by directory name
    directoryEstimates.sort((a, b) => a.directory.localeCompare(b.directory))

    // Estimate time: ~1.5s per 100 sections (API batch processing)
    const estimatedTimeSeconds = Math.ceil(totalSections / 100) * 1.5

    return {
      totalFiles,
      totalSections,
      totalTokens,
      totalCost: (totalTokens / 1_000_000) * EMBEDDING_PRICE_PER_MILLION,
      estimatedTimeSeconds,
      byDirectory: directoryEstimates,
    }
  })

// ============================================================================
// Build Embeddings
// ============================================================================

export interface FileProgress {
  readonly fileIndex: number
  readonly totalFiles: number
  readonly filePath: string
  readonly sectionCount: number
}

export interface BuildEmbeddingsOptions {
  readonly force?: boolean | undefined
  readonly provider?: EmbeddingProvider | undefined
  readonly excludePatterns?: readonly string[] | undefined
  readonly onFileProgress?: ((progress: FileProgress) => void) | undefined
}

export interface BuildEmbeddingsResult {
  readonly sectionsEmbedded: number
  readonly tokensUsed: number
  readonly cost: number
  readonly duration: number
  readonly filesProcessed: number
  readonly cacheHit?: boolean | undefined
  readonly existingVectors?: number | undefined
  readonly estimatedSavings?: number | undefined
}

export const buildEmbeddings = (
  rootPath: string,
  options: BuildEmbeddingsOptions = {},
): Effect.Effect<BuildEmbeddingsResult, Error> =>
  Effect.gen(function* () {
    const startTime = Date.now()
    const resolvedRoot = path.resolve(rootPath)
    const storage = createStorage(resolvedRoot)

    // Load indexes
    const docIndex = yield* loadDocumentIndex(storage)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!docIndex || !sectionIndex) {
      return yield* Effect.fail(
        new Error("Index not found. Run 'mdtldr index' first."),
      )
    }

    // Get or create provider
    const provider = options.provider ?? createOpenAIProvider()
    const dimensions = provider.dimensions

    // Create vector store
    const vectorStore = createVectorStore(
      resolvedRoot,
      dimensions,
    ) as HnswVectorStore
    vectorStore.setProvider(provider.name)

    // Load existing if not forcing
    if (!options.force) {
      const loaded = yield* vectorStore.load()
      if (loaded) {
        const stats = vectorStore.getStats()
        // Skip if any embeddings exist
        if (stats.count > 0) {
          const duration = Date.now() - startTime
          // Estimate savings based on existing tokens
          const estimatedSavings = (stats.totalTokens / 1_000_000) * EMBEDDING_PRICE_PER_MILLION
          return {
            sectionsEmbedded: 0,
            tokensUsed: 0,
            cost: 0,
            duration,
            filesProcessed: 0,
            cacheHit: true,
            existingVectors: stats.count,
            estimatedSavings,
          }
        }
      }
    }

    // Helper to check if a path matches exclude patterns
    const isExcluded = (docPath: string): boolean => {
      if (!options.excludePatterns?.length) return false
      return options.excludePatterns.some((pattern) => {
        const regex = new RegExp(
          '^' + pattern.replace(/\*/g, '.*').replace(/\?/g, '.') + '$',
        )
        return regex.test(docPath)
      })
    }

    // Group sections by document for efficient file reading
    const sectionsByDoc: Map<
      string,
      { section: SectionEntry; parentHeading: string | undefined }[]
    > = new Map()

    for (const section of Object.values(sectionIndex.sections)) {
      const document = docIndex.documents[section.documentPath]
      if (!document) continue

      // Skip very short sections (< 10 tokens)
      if (section.tokenCount < 10) continue

      // Check exclude patterns
      if (isExcluded(section.documentPath)) continue

      // Find parent heading if any
      let parentHeading: string | undefined
      if (section.level > 1) {
        const docSections = sectionIndex.byDocument[document.id] ?? []
        for (const sibId of docSections) {
          const sib = sectionIndex.sections[sibId]
          if (
            sib &&
            sib.level === section.level - 1 &&
            sib.startLine < section.startLine
          ) {
            parentHeading = sib.heading
          }
        }
      }

      const docPath = section.documentPath
      if (!sectionsByDoc.has(docPath)) {
        sectionsByDoc.set(docPath, [])
      }
      sectionsByDoc.get(docPath)!.push({ section, parentHeading })
    }

    if (sectionsByDoc.size === 0) {
      const duration = Date.now() - startTime
      return {
        sectionsEmbedded: 0,
        tokensUsed: 0,
        cost: 0,
        duration,
        filesProcessed: 0,
      }
    }

    // Prepare sections for embedding by reading file content
    const sectionsToEmbed: { section: SectionEntry; text: string }[] = []
    const docPaths = Array.from(sectionsByDoc.keys())
    let filesProcessed = 0

    for (let fileIndex = 0; fileIndex < docPaths.length; fileIndex++) {
      const docPath = docPaths[fileIndex]!
      const sections = sectionsByDoc.get(docPath)!
      const document = docIndex.documents[docPath]
      if (!document) continue

      // Report file progress
      if (options.onFileProgress) {
        options.onFileProgress({
          fileIndex: fileIndex + 1,
          totalFiles: docPaths.length,
          filePath: docPath,
          sectionCount: sections.length,
        })
      }

      const filePath = path.join(resolvedRoot, docPath)
      let fileContent: string
      try {
        fileContent = yield* Effect.promise(() => fs.readFile(filePath, 'utf-8'))
      } catch {
        // Skip files that can't be read
        continue
      }

      filesProcessed++
      const lines = fileContent.split('\n')

      for (const { section, parentHeading } of sections) {
        // Extract section content from file
        const content = lines
          .slice(section.startLine - 1, section.endLine)
          .join('\n')

        const text = generateEmbeddingText(
          section,
          content,
          document.title,
          parentHeading,
        )
        sectionsToEmbed.push({ section, text })
      }
    }

    if (sectionsToEmbed.length === 0) {
      const duration = Date.now() - startTime
      return {
        sectionsEmbedded: 0,
        tokensUsed: 0,
        cost: 0,
        duration,
        filesProcessed,
      }
    }

    // Generate embeddings
    const texts = sectionsToEmbed.map((s) => s.text)
    const result = yield* Effect.tryPromise({
      try: () => provider.embed(texts),
      catch: (e) =>
        new Error(
          `Embedding failed: ${e instanceof Error ? e.message : String(e)}`,
        ),
    })

    // Create vector entries
    const entries: VectorEntry[] = []
    for (let i = 0; i < sectionsToEmbed.length; i++) {
      const { section } = sectionsToEmbed[i] ?? { section: null }
      const embedding = result.embeddings[i]
      if (!section || !embedding) continue

      entries.push({
        id: section.id,
        sectionId: section.id,
        documentPath: section.documentPath,
        heading: section.heading,
        embedding,
      })
    }

    // Add to vector store
    yield* vectorStore.add(entries)
    vectorStore.addCost(result.cost, result.tokensUsed)

    // Save
    yield* vectorStore.save()

    const duration = Date.now() - startTime

    return {
      sectionsEmbedded: entries.length,
      tokensUsed: result.tokensUsed,
      cost: result.cost,
      duration,
      filesProcessed,
    }
  })

// ============================================================================
// Semantic Search
// ============================================================================

export const semanticSearch = (
  rootPath: string,
  query: string,
  options: SemanticSearchOptions = {},
): Effect.Effect<readonly SemanticSearchResult[], Error> =>
  Effect.gen(function* () {
    const resolvedRoot = path.resolve(rootPath)

    // Get provider for query embedding
    const provider = createOpenAIProvider()
    const dimensions = provider.dimensions

    // Load vector store
    const vectorStore = createVectorStore(resolvedRoot, dimensions)
    const loaded = yield* vectorStore.load()

    if (!loaded) {
      return yield* Effect.fail(
        new Error("Embeddings not found. Run 'mdtldr embed' first."),
      )
    }

    // Embed the query
    const queryResult = yield* Effect.tryPromise({
      try: () => provider.embed([query]),
      catch: (e) =>
        new Error(
          `Query embedding failed: ${e instanceof Error ? e.message : String(e)}`,
        ),
    })

    const queryVector = queryResult.embeddings[0]
    if (!queryVector) {
      return yield* Effect.fail(new Error('Failed to generate query embedding'))
    }

    // Search
    const limit = options.limit ?? 10
    const threshold = options.threshold ?? 0

    const searchResults = yield* vectorStore.search(
      queryVector,
      limit * 2,
      threshold,
    )

    // Apply path filter if specified
    let filteredResults = searchResults
    if (options.pathPattern) {
      const pattern = options.pathPattern
        .replace(/\./g, '\\.')
        .replace(/\*/g, '.*')
      const regex = new RegExp(`^${pattern}$`, 'i')
      filteredResults = searchResults.filter((r) => regex.test(r.documentPath))
    }

    // Convert to SemanticSearchResult
    const results: SemanticSearchResult[] = filteredResults
      .slice(0, limit)
      .map((r) => ({
        sectionId: r.sectionId,
        documentPath: r.documentPath,
        heading: r.heading,
        similarity: r.similarity,
      }))

    return results
  })

// ============================================================================
// Search with Content
// ============================================================================

export const semanticSearchWithContent = (
  rootPath: string,
  query: string,
  options: SemanticSearchOptions = {},
): Effect.Effect<readonly SemanticSearchResult[], Error> =>
  Effect.gen(function* () {
    const resolvedRoot = path.resolve(rootPath)
    const results = yield* semanticSearch(resolvedRoot, query, options)

    const storage = createStorage(resolvedRoot)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!sectionIndex) {
      return results
    }

    const resultsWithContent: SemanticSearchResult[] = []

    for (const result of results) {
      const section = sectionIndex.sections[result.sectionId]
      if (!section) {
        resultsWithContent.push(result)
        continue
      }

      const filePath = path.join(resolvedRoot, result.documentPath)

      try {
        const fileContent = yield* Effect.promise(() =>
          fs.readFile(filePath, 'utf-8'),
        )

        const lines = fileContent.split('\n')
        const content = lines
          .slice(section.startLine - 1, section.endLine)
          .join('\n')

        resultsWithContent.push({
          ...result,
          content,
        })
      } catch {
        resultsWithContent.push(result)
      }
    }

    return resultsWithContent
  })

// ============================================================================
// Get Embedding Stats
// ============================================================================

export interface EmbeddingStats {
  readonly hasEmbeddings: boolean
  readonly count: number
  readonly provider: string
  readonly dimensions: number
  readonly totalCost: number
  readonly totalTokens: number
}

export const getEmbeddingStats = (
  rootPath: string,
): Effect.Effect<EmbeddingStats, Error> =>
  Effect.gen(function* () {
    const resolvedRoot = path.resolve(rootPath)

    // Try to load with default dimensions
    const vectorStore = createVectorStore(resolvedRoot, 1536)
    const loaded = yield* vectorStore.load()

    if (!loaded) {
      return {
        hasEmbeddings: false,
        count: 0,
        provider: 'none',
        dimensions: 0,
        totalCost: 0,
        totalTokens: 0,
      }
    }

    const stats = vectorStore.getStats()
    return {
      hasEmbeddings: true,
      count: stats.count,
      provider: stats.provider,
      dimensions: stats.dimensions,
      totalCost: stats.totalCost,
      totalTokens: stats.totalTokens,
    }
  })

/**
 * Vector store using hnswlib-node
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'
import HierarchicalNSW from 'hnswlib-node'
import { INDEX_DIR } from '../index/types.js'
import type { VectorEntry, VectorIndex } from './types.js'

// ============================================================================
// Constants
// ============================================================================

const VECTOR_INDEX_FILE = 'vectors.bin'
const VECTOR_META_FILE = 'vectors.meta.json'
const INDEX_VERSION = 1

// ============================================================================
// Vector Store
// ============================================================================

export interface VectorStore {
  readonly rootPath: string
  readonly dimensions: number
  add(entries: VectorEntry[]): Effect.Effect<void, Error>
  search(
    vector: number[],
    limit: number,
    threshold?: number,
  ): Effect.Effect<VectorSearchResult[], Error>
  save(): Effect.Effect<void, Error>
  load(): Effect.Effect<boolean, Error>
  getStats(): VectorStoreStats
}

export interface VectorSearchResult {
  readonly id: string
  readonly sectionId: string
  readonly documentPath: string
  readonly heading: string
  readonly similarity: number
}

export interface VectorStoreStats {
  readonly count: number
  readonly dimensions: number
  readonly provider: string
  readonly totalCost: number
  readonly totalTokens: number
}

// ============================================================================
// Implementation
// ============================================================================

class HnswVectorStore implements VectorStore {
  readonly rootPath: string
  readonly dimensions: number

  private index: HierarchicalNSW.HierarchicalNSW | null = null
  private entries: Map<number, VectorEntry> = new Map()
  private idToIndex: Map<string, number> = new Map()
  private nextIndex = 0
  private provider = 'unknown'
  private totalCost = 0
  private totalTokens = 0

  constructor(rootPath: string, dimensions: number) {
    this.rootPath = path.resolve(rootPath)
    this.dimensions = dimensions
  }

  private getIndexDir(): string {
    return path.join(this.rootPath, INDEX_DIR)
  }

  private getVectorPath(): string {
    return path.join(this.getIndexDir(), VECTOR_INDEX_FILE)
  }

  private getMetaPath(): string {
    return path.join(this.getIndexDir(), VECTOR_META_FILE)
  }

  private ensureIndex(): HierarchicalNSW.HierarchicalNSW {
    if (!this.index) {
      // Initialize with space for 10000 items, will resize as needed
      this.index = new HierarchicalNSW.HierarchicalNSW(
        'cosine',
        this.dimensions,
      )
      this.index.initIndex(10000, 16, 200, 100)
    }
    return this.index
  }

  add(entries: VectorEntry[]): Effect.Effect<void, Error> {
    return Effect.sync(() => {
      const index = this.ensureIndex()

      for (const entry of entries) {
        // Skip if already exists
        if (this.idToIndex.has(entry.id)) {
          continue
        }

        const idx = this.nextIndex++

        // Resize if needed
        if (idx >= index.getMaxElements()) {
          index.resizeIndex(index.getMaxElements() * 2)
        }

        index.addPoint(entry.embedding as number[], idx)
        this.entries.set(idx, entry)
        this.idToIndex.set(entry.id, idx)
      }
    })
  }

  search(
    vector: number[],
    limit: number,
    threshold = 0,
  ): Effect.Effect<VectorSearchResult[], Error> {
    return Effect.sync(() => {
      if (!this.index || this.entries.size === 0) {
        return []
      }

      const result = this.index.searchKnn(
        vector,
        Math.min(limit, this.entries.size),
      )
      const results: VectorSearchResult[] = []

      for (let i = 0; i < result.neighbors.length; i++) {
        const idx = result.neighbors[i]
        const distance = result.distances[i]

        if (idx === undefined || distance === undefined) {
          continue
        }

        // Convert distance to similarity (cosine distance to cosine similarity)
        // hnswlib returns 1 - cosine_similarity for cosine space
        const similarity = 1 - distance

        if (similarity < threshold) {
          continue
        }

        const entry = this.entries.get(idx)
        if (entry) {
          results.push({
            id: entry.id,
            sectionId: entry.sectionId,
            documentPath: entry.documentPath,
            heading: entry.heading,
            similarity,
          })
        }
      }

      return results
    })
  }

  save(): Effect.Effect<void, Error> {
    return Effect.gen(
      function* (this: HnswVectorStore) {
        if (!this.index) {
          return
        }

        const indexDir = this.getIndexDir()
        yield* Effect.promise(() => fs.mkdir(indexDir, { recursive: true }))

        // Save the hnswlib index
        yield* Effect.promise(() =>
          this.index!.writeIndex(this.getVectorPath()),
        )

        // Save metadata
        const meta: VectorIndex = {
          version: INDEX_VERSION,
          provider: this.provider,
          dimensions: this.dimensions,
          entries: Object.fromEntries(
            Array.from(this.entries.entries()).map(([idx, entry]) => [
              idx.toString(),
              entry,
            ]),
          ),
          totalCost: this.totalCost,
          totalTokens: this.totalTokens,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        }

        yield* Effect.promise(() =>
          fs.writeFile(this.getMetaPath(), JSON.stringify(meta, null, 2)),
        )
      }.bind(this),
    )
  }

  load(): Effect.Effect<boolean, Error> {
    return Effect.gen(
      function* (this: HnswVectorStore) {
        const vectorPath = this.getVectorPath()
        const metaPath = this.getMetaPath()

        // Check if files exist
        const filesExist = yield* Effect.tryPromise({
          try: async () => {
            await fs.access(vectorPath)
            await fs.access(metaPath)
            return true
          },
          catch: () => false as const,
        }).pipe(Effect.catchAll(() => Effect.succeed(false)))

        if (!filesExist) {
          return false
        }

        // Load metadata first
        const metaContent = yield* Effect.promise(() =>
          fs.readFile(metaPath, 'utf-8'),
        )
        const meta = JSON.parse(metaContent) as VectorIndex

        // Verify dimensions match
        if (meta.dimensions !== this.dimensions) {
          return false
        }

        // Load the hnswlib index
        this.index = new HierarchicalNSW.HierarchicalNSW(
          'cosine',
          this.dimensions,
        )
        yield* Effect.promise(() => this.index!.readIndex(vectorPath))

        // Restore entries
        this.entries.clear()
        this.idToIndex.clear()
        this.nextIndex = 0

        for (const [idxStr, entry] of Object.entries(meta.entries)) {
          const idx = parseInt(idxStr, 10)
          this.entries.set(idx, entry)
          this.idToIndex.set(entry.id, idx)
          this.nextIndex = Math.max(this.nextIndex, idx + 1)
        }

        this.provider = meta.provider
        this.totalCost = meta.totalCost
        this.totalTokens = meta.totalTokens

        return true
      }.bind(this),
    )
  }

  getStats(): VectorStoreStats {
    return {
      count: this.entries.size,
      dimensions: this.dimensions,
      provider: this.provider,
      totalCost: this.totalCost,
      totalTokens: this.totalTokens,
    }
  }

  setProvider(name: string): void {
    this.provider = name
  }

  addCost(cost: number, tokens: number): void {
    this.totalCost += cost
    this.totalTokens += tokens
  }
}

